#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float1 d = 0.005;
    float1 dx = ( GetBlur2(vUv + vec2(d,0)) - GetBlur2(vUv-vec2(d,0)) ).y;
    float1 dy = ( GetBlur2(vUv + vec2(0,d)) - GetBlur2(vUv-vec2(0,d)) ).y;
    vec2 my_uv = vUv - vec2(dx,dy)*0.01;



    vec2 v = 0.01;
    ret.y = texture( sampler_fc_main, my_uv-floor(my_uv)).y;


    ret.y += (ret.y - GetBlur3(my_uv-floor(my_uv)).y)*.1;
    ret.y += 0.006-GetBlur3(vUv-floor(vUv)).x*5;

    ret.y = mix( ret.y, lum(ret).x, 0);

//--------------------------------

    d = 0.01;
    my_uv = vec2(-dy,dx)*0.05;

    dx = ( GetBlur2(vUv + vec2(d,0)) - GetBlur2(vUv-vec2(d,0)) ).z;
    dy = ( GetBlur2(vUv + vec2(0,d)) - GetBlur2(vUv-vec2(0,d)) ).z;
    my_uv += vUv - vec2(dx,dy)*0.005;



    v = 0.01;
    ret.z =texture( sampler_fw_main, my_uv - floor(my_uv)).z;


    ret.z += (ret.z - GetBlur3(my_uv-floor(my_uv)).z)*0.13;
    ret.z *= 0.95;
    ret.z += 0.03-GetBlur3(vUv-floor(vUv)).x - texture( sampler_main, my_uv - floor(my_uv)).y*0.05;

    ret.x = texture( sampler_main, vUvOriginal).x - 0.3;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float rad_lq = vRadius * length(uTexSize.xy)*0.5;
    float ang_lq = vAngle;
    vec2 uv_temp1 = (vUv - 0.5) * uTexSize.xy;
    float rad_hq = length(uv_temp1);
    float ang_hq = atan(-uv_temp1.y, uv_temp1.x);

    vec2 uv2 = (vUv - 0.5);
    float rad2 = rad_lq*0.8;
    float ang2 = ang_lq * M_INV_PI_2;

        // ROTATION OVER TIME
        #if 1
          ang2 += uTime*0.025;   //rotate over uTime
        #endif

        // FIN TYPE
        float fins = 3 + floor(rand_preset.z*5.95);
        #if 1     // SHARP FINS
          ang2 = fract(ang2*fins)/fins;
              // ENABLE THIS TO MAKE THE FINS ALTERNATE: (seamless!)
              ang2 = abs(ang2 - 0.5/fins);
        #else     // COSINE FINS - a bit slow
          ang2 = cos(ang2*M_PI_2*fins) * 0.023;
        #endif

        // RADIAL KALEIDOSCOPING?
        #if 0
          rad2 *= g_fTexSize.z;
            // choose one:
            //rad2 = mix(rad2, fract(rad2*3)/3.0, 0.5);
            rad2 = cos(rad2*5);
            //rad2 = sqrt(rad2)*0.5;
            //rad2 += abs(fract(rad2*7)-0.5)/7.0 * 1.15;  // stepifier
            //rad2 += cos(rad2*61)*0.02;
          rad2 *= g_fTexSize.x;
        #endif

    ang2 *= M_PI_2;
    uv2 = 0.5 + rad2*vec2(cos(ang2),sin(ang2))*uTexSize.zw;

    ret = texture(sampler_main,uv2).y*vec3(0.6,0.2,1.5) + texture(sampler_fw_main,uv2).x*vec3(1,0.66,0) - texture(sampler_main,uv2).z*vec3(-0.6,1,2);

  fragColor = ret;
}
